mapper.select:
SELECT DOCTOR_ID AS doctorId, NAME AS name, TITLE AS title, DEPARTMENT AS department, HOSPITAL AS hospital, AVATAR_ID AS avatarId, INTRODUCTION AS introduction, SPECIALTIES AS specialties, RATING AS rating, CONSULTATION_COUNT AS consultationCount, STATUS AS status FROM DIABETES_DOCTOR.DOCTORS WHERE IS_DELETED = 0
AND DEPARTMENT = #{department}
AND STATUS = #{status}
AND (NAME LIKE CONCAT('%', #{keyword}, '%') OR DEPARTMENT LIKE CONCAT('%', #{keyword}, '%') OR HOSPITAL LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY STATUS ASC, CONSULTATION_COUNT DESC

mapper.update:
UPDATE DIABETES_DOCTOR.DOCTORS
SET CONSULTATION_COUNT = CONSULTATION_COUNT + 1
WHERE DOCTOR_ID = #{doctorId}
